const LOCALES = { en, fr, de, es, it, nl, pt, no, pl, cs, sv };
const FALLBACK = en;
function pickTranslations(haLanguage) {
  if (!haLanguage) {
    return FALLBACK;
  }
  const lower = haLanguage.toLowerCase();
  if (LOCALES[lower]) {
    return LOCALES[lower];
  }
  const root = lower.split("-")[0];
  if (LOCALES[root]) {
    return LOCALES[root];
  }
  return FALLBACK;
}
